func randomPalette() color.Palette {
	p := make([]color.Color, circleCount+1)

	p[0] = color.RGBA{0xFF, 0xFF, 0xFF, 0x00}

	prim := color.RGBA{
		uint8(randIntn(129)),
		uint8(randIntn(129)),
		uint8(randIntn(129)),
		0xFF,
	}
	p[1] = prim

	for i := 2; i <= circleCount; i++ {
		p[i] = randomBrightness(prim, 255)
	}
	return p
}
